import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import PoeticSnakeGame from './PoeticSnakeGame';

const root = ReactDOM.createRoot(
  document.getElementById('root') as HTMLElement
);
root.render(
  <React.StrictMode>
    <PoeticSnakeGame />
  </React.StrictMode>
);
